    ('PLO', '15', 2026, 'Altera dispositivos da Lei Municipal nº 2.654, de 30 de janeiro de 2026, para instituir a Carteira de Identificação da Pessoa com Fibromialgia como meio preferencial de comprovação do atendimento prioritário, dispor sobre sua emissão gratuita pela SEMSA, estabelecer obrigações aos estabelecimentos e vedar exigências e constrangimentos indevidos.', 'Nao informado', 'SAPL Rio Branco', 'SAPL-RB:41684', 'http://sapl.riobranco.ac.leg.br/media/sapl/public/materialegislativa/2026/41684/projeto_de_lei_cria_carteirinha_pessoa_com_fibromialgia.pdf', 'andre-kamai-rio-branco-sapl-autoria-principal-ampliado-parcial-20260507', 'inventario_ampliado_parcial_sapl_rio_branco_autoria_principal_20260507', 'andre-kamai-rio-branco-sapl-completo-autoria-principal-tipos-legislativos-cutoff-20260511', 'inventario_completo_sapl_rio_branco_autoria_principal_tipos_legislativos_cutoff_20260511', '{"source":"SAPL Rio Branco","data_real":true,"fluxo":"Legislacao full-site","slug":"andre-kamai","tabela_alvo":"projetos_lei","legislacao_mandato_executivo_mixed":false,"curation_batch_id":"legislacao-andre-kamai-sapl-rio-branco-completo-20260511","migration_version":"20260511233000","coverage_id":"andre-kamai-rio-branco-sapl-completo-autoria-principal-tipos-legislativos-cutoff-20260511","coverage_scope":"inventario_completo_sapl_rio_branco_autoria_principal_tipos_legislativos_cutoff_20260511","previous_coverage_id":"andre-kamai-rio-branco-sapl-autoria-principal-ampliado-parcial-20260507","previous_coverage_scope":"inventario_ampliado_parcial_sapl_rio_branco_autoria_principal_20260507","coverage_status":"completo_escopado","coverage_public_status":"parlamentar_complete","coverage_policy":"sapl_rio_branco_autoria_principal_tipos_legislativos_v1","coverage_cutoff":"2026-05-11","coverage_rows":18,"recorte_publico":"autoria parlamentar principal no SAPL Rio Branco por author_id=138 em tipos PLO, PDL e PRE, com cutoff em 11/05/2026","fonte_oficial":"Câmara Municipal de Rio Branco","