    ('PLO', '6', 2026, 'Dispõe sobre a instituição de mecanismos de incentivo cívico e de responsabilidade viária no Município de Rio Branco, autorizando a conversão do pagamento de multas de trânsito de natureza leve, de competência municipal, em doação de sangue ou cadastro como doador de medula óssea, e estabelece benefício fiscal condicionado à inexistência de infrações de trânsito e à doação regular de sangue, e dá outras providências. A', 'Nao informado', 'SAPL Rio Branco', 'SAPL-RB:40859', 'http://sapl.riobranco.ac.leg.br/media/sapl/public/materialegislativa/2026/40859/projeto_de_lei_institui_incentivo_civico_com_doacao_de_sangue_para_pagamento.pdf', 'andre-kamai-rio-branco-sapl-autoria-principal-ampliado-parcial-20260507', 'inventario_ampliado_parcial_sapl_rio_branco_autoria_principal_20260507', 'andre-kamai-rio-branco-sapl-completo-autoria-principal-tipos-legislativos-cutoff-20260511', 'inventario_completo_sapl_rio_branco_autoria_principal_tipos_legislativos_cutoff_20260511', '{"source":"SAPL Rio Branco","data_real":true,"fluxo":"Legislacao full-site","slug":"andre-kamai","tabela_alvo":"projetos_lei","legislacao_mandato_executivo_mixed":false,"curation_batch_id":"legislacao-andre-kamai-sapl-rio-branco-completo-20260511","migration_version":"20260511233000","coverage_id":"andre-kamai-rio-branco-sapl-completo-autoria-principal-tipos-legislativos-cutoff-20260511","coverage_scope":"inventario_completo_sapl_rio_branco_autoria_principal_tipos_legislativos_cutoff_20260511","previous_coverage_id":"andre-kamai-rio-branco-sapl-autoria-principal-ampliado-parcial-20260507","previous_coverage_scope":"inventario_ampliado_parcial_sapl_rio_branco_autoria_principal_20260507","coverage_status":"completo_escopado","coverage_public_status":"parlamentar_complete","coverage_policy":"sapl_rio_branco_autoria_principal_tipos_legislativos_v1","coverage_cutoff":"2026-05-11","coverage_rows":18,"recorte_publico":"autoria parlamentar principal no SAPL Rio Branco por author_id=138 em tip