DO $$
DECLARE
  cand_id uuid;
  duplicate_count int;
  projetos_total int;
  old_count int;
  complete_count int;
  target_with_other_coverage int;
  lme_total int;
  lme_target_coverage int;
BEGIN
  SELECT id INTO cand_id FROM candidatos WHERE slug = 'andre-kamai' AND publicavel = true;

  IF cand_id IS NULL THEN
    RAISE NOTICE 'andre-kamai: candidato publico ausente neste banco local/CI minimo; verificacao pulada';
    RETURN;
  END IF;

  SELECT count(*) - count(DISTINCT proposicao_id_api)
  INTO duplicate_count
  FROM _promote_andre_kamai_sapl_completo;

  IF duplicate_count <> 0 THEN
    RAISE EXCEPTION 'Pre-condicao andre-kamai: seed contem % proposicao_id_api duplicadas', duplicate_count;
  END IF;

  SELECT count(*) INTO projetos_total FROM projetos_lei WHERE candidato_id = cand_id;
  SELECT count(*) INTO old_count FROM projetos_lei WHERE candidato_id = cand_id AND coverage_id = 'andre-kamai-rio-branco-sapl-autoria-principal-ampliado-parcial-20260507';
  SELECT count(*) INTO complete_count FROM projetos_lei WHERE candidato_id = cand_id AND coverage_id = 'andre-kamai-rio-branco-sapl-completo-autoria-principal-tipos-legislativos-cutoff-20260511';
  SELECT count(*) INTO lme_total FROM legislacao_mandato_executivo WHERE candidato_id = cand_id;

  SELECT count(*)
  INTO target_with_other_coverage
  FROM projetos_lei pl
  JOIN _promote_andre_kamai_sapl_completo seed
    ON seed.proposicao_id_api = pl.proposicao_id_api
  WHERE pl.candidato_id = cand_id
    AND pl.coverage_id IS NOT NULL
    AND pl.coverage_id NOT IN (seed.previous_coverage_id, seed.coverage_id);

  SELECT count(*)
  INTO lme_target_coverage
  FROM legislacao_mandato_executivo
  WHERE candidato_id = cand_id
    AND metadata->>'coverage_id' = 'andre-kamai-rio-branco-sapl-completo-autoria-principal-tipos-legislativos-cutoff-20260511';

  IF projetos_total <> 18 THEN
    RAISE EXCEPTION 'Pre-condicao andre-kamai: projetos_lei total esperado 18, encontrado %', projetos_total;
  END IF;
  IF NOT (old_count = 18 OR complete_count = 18) THEN
    RAISE EXCEPTION 'Pre-condicao andre-kamai: esperado old ou complete count 18, old=%, complete=%', old_count, complete_count;
  END IF;
  IF target_with_other_coverage <> 0 THEN
    RAISE EXCEPTION 'Pre-condicao andre-kamai: % rows alvo ja tem coverage_id divergente', target_with_other_coverage;
  END IF;
  IF lme_total <> 0 THEN
    RAISE EXCEPTION 'Pre-condicao andre-kamai: legislacao_mandato_executivo esperado 0, encontrado %', lme_total;
  END IF;
  IF lme_target_coverage <> 0 THEN
    RAISE EXCEPTION 'Pre-condicao andre-kamai: coverage parlamentar novo nao pode existir em LME, encontrado %', lme_target_coverage;
  END IF;
END $$;

WITH target AS (
  SELECT c.id AS candidato_id
  FROM candidatos c
  WHERE c.slug = 'andre-kamai' AND c.publicavel = true
)
INSERT INTO projetos_lei (
  candidato_id,
  tipo,
  numero,
  ano,
  ementa,
  situacao,
  fonte,
  proposicao_id_api,
  url_inteiro_teor,
  coverage_id,
  coverage_scope,
  metadata
)
SELECT
  target.candidato_id,
  seed.tipo,
  seed.numero,
  seed.ano,
  seed.ementa,
  seed.situacao,
  seed.fonte,
  seed.proposicao_id_api,
  seed.url_inteiro_teor,
  seed.coverage_id,
  seed.coverage_scope,
  seed.metadata
FROM target
CROSS JOIN _promote_andre_kamai_sapl_completo AS seed
ON CONFLICT (candidato_id, proposicao_id_api) DO UPDATE SET
  tipo = EXCLUDED.tipo,
  numero = EXCLUDED.numero,
  ano = EXCLUDED.ano,
  ementa = EXCLUDED.ementa,
  situacao = EXCLUDED.situacao,
  fonte = EXCLUDED.fonte,
  url_inteiro_teor = EXCLUDED.url_inteiro_teor,
  coverage_id = EXCLUDED.coverage_id,
  coverage_scope = EXCLUDED.coverage_scope,
  metadata = EXCLUDED.metadata;

DO $$
DECLARE
  cand_id uuid;
  projetos_total int;
  complete_count int;
  old_count int;
  metadata_ok int;
  lme_total int;
  lme_target_count int;
BEGIN
  SELECT id INTO cand_id FROM candidatos WHERE slug = 'andre-kamai' AND publicavel = true;

  IF cand_id IS NULL THEN
    RAISE NOTICE 'andre-kamai: candidato publico ausente neste banco local/CI minimo; verificacao pulada';
    RETURN;
  END IF;

  SELECT count(*) INTO projetos_total FROM projetos_lei WHERE candidato_id = cand_id;
  SELECT count(*) INTO complete_count FROM projetos_lei WHERE candidato_id = cand_id AND coverage_id = 'andre-kamai-rio-branco-sapl-completo-autoria-principal-tipos-legislativos-cutoff-20260511';
  SELECT count(*) INTO old_count FROM projetos_lei WHERE candidato_id = cand_id AND coverage_id = 'andre-kamai-rio-branco-sapl-autoria-principal-ampliado-parcial-20260507';
  SELECT count(*) INTO lme_total FROM legislacao_mandato_executivo WHERE candidato_id = cand_id;
  SELECT count(*) INTO lme_target_count
  FROM legislacao_mandato_executivo
  WHERE candidato_id = cand_id
    AND metadata->>'coverage_id' = 'andre-kamai-rio-branco-sapl-completo-autoria-principal-tipos-legislativos-cutoff-20260511';
  SELECT count(*) INTO metadata_ok
  FROM projetos_lei
  WHERE candidato_id = cand_id
    AND coverage_id = 'andre-kamai-rio-branco-sapl-completo-autoria-principal-tipos-legislativos-cutoff-20260511'
    AND coverage_scope = 'inventario_completo_sapl_rio_branco_autoria_principal_tipos_legislativos_cutoff_20260511'
    AND metadata->>'coverage_id' = 'andre-kamai-rio-branco-sapl-completo-autoria-principal-tipos-legislativos-cutoff-20260511'
    AND metadata->>'coverage_scope' = 'inventario_completo_sapl_rio_branco_autoria_principal_tipos_legislativos_cutoff_20260511'
    AND metadata->>'coverage_status' = 'completo_escopado'
    AND metadata->>'coverage_public_status' = 'parlamentar_complete'
    AND metadata->>'tabela_alvo' = 'projetos_lei'
    AND metadata->>'legislacao_mandato_executivo_mixed' = 'false'
    AND metadata->>'autoria_principal_verificada' = 'true';

  IF projetos_total <> 18 THEN
    RAISE EXCEPTION 'Pos-apply andre-kamai: projetos_lei total esperado 18, encontrado %', projetos_total;
  END IF;
  IF complete_count <> 18 THEN
    RAISE EXCEPTION 'Pos-apply andre-kamai: rows complete esperadas 18, encontradas %', complete_count;
  END IF;
  IF old_count <> 0 THEN
    RAISE EXCEPTION 'Pos-apply andre-kamai: coverage antigo esperado 0, encontrado %', old_count;
  END IF;
  IF metadata_ok <> 18 THEN
    RAISE EXCEPTION 'Pos-apply andre-kamai: metadata completa esperada 18, encontrada %', metadata_ok;
  END IF;
  IF lme_total <> 0 THEN
    RAISE EXCEPTION 'Pos-apply andre-kamai: legislacao_mandato_executivo esperado 0, encontrado %', lme_total;
  END IF;
  IF lme_target_count <> 0 THEN
    RAISE EXCEPTION 'Pos-apply andre-kamai: coverage parlamentar novo nao pode existir em LME, encontrado %', lme_target_count;
  END IF;

  RAISE NOTICE 'Pos-apply andre-kamai SAPL Rio Branco completo: projetos_lei=% coverage_rows=%', projetos_total, complete_count;
END $$;
